{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyO+LoL4h2S73wxnhbLZJ49e"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","source":["import streamlit as st\n","import pandas as pd\n","\n","# Configuration de la page principale\n","st.set_page_config(\n","    page_title=\"CINEVASION\",\n","    page_icon=\"🎬\",\n","    layout=\"wide\"\n",")\n","\n","# Charger le fichier CSS\n","def load_css(css_file):\n","    try:\n","        with open(css_file, \"r\") as f:\n","            st.markdown(f\"<style>{f.read()}</style>\", unsafe_allow_html=True)\n","    except FileNotFoundError:\n","        st.warning(f\"Le fichier CSS '{css_file}' est introuvable.\")\n","\n","# Charger les styles\n","load_css(\"cinevasion/css/style.css\")\n","\n","# Charger les données des films\n","@st.cache_data\n","def load_data():\n","    return pd.read_csv(\"cinevasion/csv/films_acteurs.csv\")\n","\n","films = load_data()\n","\n","# Titre principal\n","st.title(\"CINEVASION\")\n","st.subheader(\"Explorez et découvrez des films 🎬\")\n","\n","# Barre de recherche\n","with st.container():\n","    st.subheader(\"Recherche rapide\")\n","    film_input = st.text_input(\"Entrez le titre d'un film :\", placeholder=\"Ex : Titanic\")\n","    if st.button(\"Rechercher un film\"):\n","        if film_input:\n","            selected_film = films[films[\"title\"].str.contains(film_input, case=False, na=False)]\n","            if not selected_film.empty:\n","                st.session_state[\"selected_film_tconst\"] = selected_film.iloc[0][\"tconst\"]\n","                st.session_state[\"go_to_details\"] = True\n","                st.experimental_set_query_params(page=\"details_page\")\n","            else:\n","                st.warning(\"Aucun film ne correspond à votre recherche.\")\n","        else:\n","            st.warning(\"Veuillez entrer un titre de film.\")\n","\n","# Filtres pour explorer les films\n","st.subheader(\"Filtres pour explorer les films\")\n","col1, col2, col3 = st.columns(3)\n","\n","with col1:\n","    decades = sorted(films[\"release_date\"].dropna().str[:4].astype(int).unique() // 10 * 10)\n","    selected_decade = st.selectbox(\"Décennie\", [\"\"] + [f\"{decade}s\" for decade in decades])\n","\n","with col2:\n","    genres = sorted(set(g for genre_list in films[\"genres\"].dropna() for g in genre_list.split(\"|\")))\n","    selected_genre = st.selectbox(\"Genre\", [\"\"] + genres)\n","\n","with col3:\n","    countries = sorted(films[\"origin_country\"].dropna().unique())\n","    selected_country = st.selectbox(\"Pays d'origine\", [\"\"] + countries)\n","\n","# Appliquer les filtres\n","filtered_films = films.copy()\n","\n","if selected_decade:\n","    filtered_films = filtered_films[filtered_films[\"release_date\"].str[:4].astype(int) // 10 * 10 == int(selected_decade[:-1])]\n","\n","if selected_genre:\n","    filtered_films = filtered_films[filtered_films[\"genres\"].str.contains(selected_genre, na=False)]\n","\n","if selected_country:\n","    filtered_films = filtered_films[filtered_films[\"origin_country\"] == selected_country]\n","\n","# Afficher les films filtrés\n","if filtered_films.empty:\n","    st.warning(\"Aucun film ne correspond à vos critères.\")\n","else:\n","    st.subheader(\"Résultats\")\n","    cols = st.columns(5)\n","    for i, (_, row) in enumerate(filtered_films.head(5).iterrows()):\n","        with cols[i]:\n","            st.image(row[\"poster_path\"], use_column_width=True)\n","            st.write(f\"**{row['title']}**\")\n","            st.caption(f\"Genres : {row['genres']}\")\n","\n","# Navigation entre les pages\n","st.sidebar.title(\"Navigation\")\n","page = st.sidebar.radio(\"Pages\", [\"Home\", \"Recommendations\", \"Similarity Page\"])\n","\n","if page == \"Recommendations\":\n","    st.experimental_set_query_params(page=\"recommendations_page\")\n","elif page == \"Similarity Page\":\n","    st.experimental_set_query_params(page=\"similarity_page\")"],"metadata":{"id":"5UP_7r1aXhyY"},"execution_count":null,"outputs":[]}]}